package main

import (
    "testing"
)

func StringLength(s string) int {
    return len(s)
}

func TestStringLength(t *testing.T) {
    tests := []struct {
        name     string
        input    string
        expected int
    }{
        {"empty", "", 0},
        {"hello", "hello", 5},
        {"hello world", "hello world", 11},
        {"two spaces", "  ", 2},
        {"single char", "a", 1},
    }

    for _, tt := range tests {
        t.Run(tt.name, func(t *testing.T) {
            result := StringLength(tt.input)
            if result != tt.expected {
                t.Errorf("StringLength(%q) = %d; want %d", tt.input, result, tt.expected)
            }
        })
    }
}
